    constructor(address _bunit, address initialOwner) Ownable(initialOwner) EIP712("BUnitAirdrop", "1") {
        bunit = IERC20(_bunit);
        claimAmount = 20 * 1e6;
        beamioIndexerDiamond = DEFAULT_BEAMIO_INDEXER;
