    /**
     * @dev Owner 修改免费池单次申领数量 (6 decimals)。
     */
    function setClaimAmount(uint256 _amount) external onlyOwner {
        if (_amount == 0) revert InvalidConfig();
        uint256 old = claimAmount;
        claimAmount = _amount;
